  .gbm-solar-right .rtitle{
    font-size:42px;
    font-weight:950;
    line-height:1.08;
    margin:0 0 10px;
    color:var(--solar-dark);
  }

  .gbm-solar-right .rsub{
    margin:0 0 20px;
    font-size:23px;
    line-height:1.35;
    font-weight:760;
    color:#334155;
  }

  .gbm-solar-qr-wrap{
    background:#fff;
    border-radius:24px;
    padding:20px;
    box-shadow:0 14px 36px rgba(0,0,0,.10);
    display:flex;
    align-items:center;
    justify-content:center;
    margin:8px auto 18px;
    width:min(100%, 350px);
    aspect-ratio:1 / 1;
  }

  .gbm-solar-qr-wrap img{
    width:100%;
    height:100%;
    object-fit:contain;
    display:block;
  }

  .gbm-solar-url{
    background:#ffffff;
    border:1px solid #dbe7e1;
    border-radius:18px;
    padding:18px 20px;
    text-align:center;
  }

  .gbm-solar-url .small{
    display:block;
    font-size:19px;
    font-weight:800;
    color:#475569;
    margin-bottom:8px;
  }

  .gbm-solar-url .link{
    display:block;
    font-size:28px;
    line-height:1.2;
    font-weight:950;
    color:var(--solar-deep);
    word-break:break-word;
  }

  .gbm-solar-footerline{
    height:4px;
    width:100%;
    border-radius:999px;
    background:linear-gradient(
      90deg,
      rgba(244,197,66,.0),
      rgba(244,197,66,.9),
      rgba(25,198,182,.9),
      rgba(25,198,182,.0)
    );
    opacity:.95;
  }

  @media (max-width:1400px){
